function UserCard({ name, avatarUrl, isOnline, hasUnreadMessages }) {
  return (
    <div className="user-card">
      <img src={avatarUrl} alt={name} />
      <span>{name}</span>
      {isOnline && <span className="badge-online">Online</span>}
      {hasUnreadMessages && <span className="badge-unread">New messages</span>}
    </div>
  );
}
